1	{{ with hugo.Data.hero }}
2	{{ if .enable }}
3	<section class="hero" id="home">
4	  <div class="container">
5	    <div class="row align-items-center">
6	      <div class="col-lg-7">
7	        <div class="hero_content">
8	          <span class="hero_eyebrow">{{ .eyebrow }}</span>
9	          <h1 class="hero_headline">{{ .headlinePrefix }} <span class="accent">{{ .headlineAccent }}</span> {{ .headlineSuffix }}</h1>
10	          <p class="hero_subhead">{{ .subhead }}</p>
11	          <div class="hero_ctas">
12	            <a class="btn btn-lg btn-primary btn-zoom hero_cta-primary"
13	              href="{{ .buttonURL | absURL }}">{{ .buttonName }} →</a>
14	            <a class="btn btn-lg btn-outline-secondary btn-zoom hero_cta-secondary"
15	              href="{{ .button2URL | absURL }}">{{ .button2Name }}</a>
16	          </div>
17	        </div>
18	      </div>
19	      <div class="col-lg-5">
20	        <div class="hero_figure">
21	          <div class="hero_figure-blob blob-wrap">
22	            {{ partial "blob.html" (dict "id" "hero-blob-gradient") }}
23	          </div>
24	          {{ with resources.Get .image }}
25	          {{ $hero500 := .Fill "500x625 Top jpg q82" }}
26	          {{ $hero750 := .Fill "750x938 Top jpg q82" }}
27	          {{ $hero1000 := .Fill "1000x1250 Top jpg q82" }}
28	          {{ $hero1400 := .Fill "1400x1750 Top jpg q82" }}
29	          {{ $hero500Webp := .Fill "500x625 Top webp q75 picture" }}
30	          {{ $hero750Webp := .Fill "750x938 Top webp q75 picture" }}
31	          {{ $hero1000Webp := .Fill "1000x1250 Top webp q75 picture" }}
32	          {{ $hero1400Webp := .Fill "1400x1750 Top webp q75 picture" }}
33	          {{ $sizes := "(min-width: 1400px) 500px, (min-width: 1200px) 430px, (min-width: 992px) 360px, (min-width: 768px) 696px, (min-width: 576px) 516px, calc(100vw - 24px)" }}
34	          <picture class="hero_figure-photo">
35	            <source type="image/webp" sizes="{{ $sizes }}"
36	              srcset="{{ $hero500Webp.RelPermalink }} 500w, {{ $hero750Webp.RelPermalink }} 750w, {{ $hero1000Webp.RelPermalink }} 1000w, {{ $hero1400Webp.RelPermalink }} 1400w">
37	            <img src="{{ $hero750.RelPermalink }}" sizes="{{ $sizes }}"
38	              srcset="{{ $hero500.RelPermalink }} 500w, {{ $hero750.RelPermalink }} 750w, {{ $hero1000.RelPermalink }} 1000w, {{ $hero1400.RelPermalink }} 1400w"
39	              width="{{ $hero750.Width }}" height="{{ $hero750.Height }}" fetchpriority="high"
40	              alt="{{ site.Title }}, {{ site.Params.subtitle }}" style='
41	                -webkit-mask: url({{ "images/hero/hero-mask-svg.svg" | absURL }});
42	                -webkit-mask-repeat: no-repeat;
43	                -webkit-mask-size: contain;
44	                -webkit-mask-position: center center;
45	                mask: url({{ "images/hero/hero-mask-svg.svg" | absURL }});
46	                mask-repeat: no-repeat;
47	                mask-size: contain;
48	                mask-position: center center;
49	              '>
50	          </picture>
51	          {{ end }}
52	
53	          {{ if .videoURL }}
54	          <a href="{{ .videoURL }}" class="hero_video-badge popup-button"
55	            data-video-title="{{ .videoLabel }}">
56	            <span class="hero_video-badge_dot"></span>
57	            <span class="hero_video-badge_label"><span aria-hidden="true">▶</span> Watch: {{ .videoLabel }}</span>
58	          </a>
